{
  "sentences": [
    {
      "text": "你要不要一個塑膠袋？",
      "pinyin": "Nǐ yào bù yào yī gè sù jiāo dài?",
      "pinyin_numeric": "ni3 yao4 bu4 yao4 yi1 ge4 su4 jiao1 dai4",
      "translation_en": "Do you want a plastic bag?",
      "translation_ko": "비닐봉지 하나 필요하세요?"
    },
    {
      "text": "你要買這個便當嗎？",
      "pinyin": "Nǐ yào mǎi zhè ge biàn dāng ma?",
      "pinyin_numeric": "ni3 yao4 mai3 zhe4 ge4 bian4 dang1 ma0",
      "translation_en": "Do you want to buy this bento box?",
      "translation_ko": "이 도시락을 사시겠어요?"
    },
    {
      "text": "要不要一個環保袋？",
      "pinyin": "Yào bù yào yī gè huán bǎo dài?",
      "pinyin_numeric": "yao4 bu4 yao4 yi1 ge4 huan2 bao3 dai4",
      "translation_en": "Would you like an eco-friendly bag?",
      "translation_ko": "에코백 하나 드릴까요?"
    },
    {
      "text": "你要不要買一送一的餅乾？",
      "pinyin": "Nǐ yào bù yào mǎi yī sòng yī de bǐng gān?",
      "pinyin_numeric": "ni3 yao4 bu4 yao4 mai3 yi1 song4 yi1 de0 bing3 gan1",
      "translation_en": "Do you want to buy the buy-one-get-one-free cookies?",
      "translation_ko": "하나 사면 하나 더 주는 쿠키를 사시겠어요?"
    },
    {
      "text": "你要不要一張收據？",
      "pinyin": "Nǐ yào bù yào yī zhāng shōu jù?",
      "pinyin_numeric": "ni3 yao4 bu4 yao4 yi1 zhang1 shou1 ju4",
      "translation_en": "Do you want a receipt?",
      "translation_ko": "영수증 필요하세요?"
    },
    {
      "text": "你要用現金付款嗎？",
      "pinyin": "Nǐ yào yòng xiàn jīn fù kuǎn ma?",
      "pinyin_numeric": "ni3 yao4 yong4 xian4 jin1 fu4 kuan3 ma0",
      "translation_en": "Do you want to pay with cash?",
      "translation_ko": "현금으로 결제하시겠어요?"
    },
    {
      "text": "你要不要用載具？",
      "pinyin": "Nǐ yào bù yào yòng zài jù?",
      "pinyin_numeric": "ni3 yao4 bu4 yao4 yong4 zai4 ju4",
      "translation_en": "Do you want to use the receipt carrier?",
      "translation_ko": "영수증 저장 서비스를 이용하시겠어요?"
    },
    {
      "text": "你要加熱這個飯糰嗎？",
      "pinyin": "Nǐ yào jiā rè zhè ge fàn tuán ma?",
      "pinyin_numeric": "ni3 yao4 jia1 re4 zhe4 ge4 fan4 tuan2 ma0",
      "translation_en": "Do you want to heat up this rice ball?",
      "translation_ko": "이 주먹밥을 데워 드릴까요?"
    },
    {
      "text": "你要不要一杯小杯的拿鐵？",
      "pinyin": "Nǐ yào bù yào yī bēi xiǎo bēi de ná tiě?",
      "pinyin_numeric": "ni3 yao4 bu4 yao4 yi1 bei1 xiao3 bei1 de0 na2 tie3",
      "translation_en": "Do you want a small latte?",
      "translation_ko": "작은 라떼 한 잔 드릴까요?"
    },
    {
      "text": "你要不要買這個特價的泡麵？",
      "pinyin": "Nǐ yào bù yào mǎi zhè ge tè jià de pào miàn?",
      "pinyin_numeric": "ni3 yao4 bu4 yao4 mai3 zhe4 ge4 te4 jia4 de0 pao4 mian4",
      "translation_en": "Do you want to buy this instant noodle on sale?",
      "translation_ko": "이 할인 중인 라면을 사시겠어요?"
    }
  ]
}
